package org.apache.commons.jxpath.ri.model.dom.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.jxpath.JXPathContext;
import org.apache.commons.jxpath.Pointer;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.apache.commons.jxpath.xml.DocumentContainer;

import static org.junit.Assert.*;

public class StepDefs {

    private JXPathContext context;
    private Object result;

    @Given("a DOM model with a root element named {string}")
    public void a_DOM_model_with_a_root_element_named(String elementName) {
        try {
            // Create a simple DOM document with the specified root element
            javax.xml.parsers.DocumentBuilderFactory factory = javax.xml.parsers.DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true); // Important for DOM operations
            javax.xml.parsers.DocumentBuilder builder = factory.newDocumentBuilder();
            Document doc = builder.newDocument();

            // Create the root element
            Element root = doc.createElement(elementName);
            doc.appendChild(root);

            // Create JXPath context with the document
            this.context = JXPathContext.newContext(doc);
        } catch (Exception e) {
            throw new RuntimeException("Failed to create DOM model", e);
        }
    }

    @When("I evaluate the XPath {string}")
    public void i_evaluate_the_XPath(String xpathExpression) {
        try {
            // Evaluate the XPath expression
            this.result = context.selectSingleNode(xpathExpression);
        } catch (Exception e) {
            // Store the exception for later verification if needed
            this.result = e;
        }
    }

    @Then("the result should be a pointer to the {string} Element")
    public void the_result_should_be_a_pointer_to_the_Element(String elementName) {
        // Check if the result is an Element and has the correct tag name
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be an Element", result instanceof org.w3c.dom.Element);

        Element element = (Element) result;
        assertEquals("Element should have the correct tag name", elementName, element.getTagName());
    }
}
